def render_hybrid_style_instruction(query_style_target: str) -> str:
    """Render the recovered Hybrid style-instruction block."""
    return HYBRID_STYLE_INSTRUCTION.format(query_style_target=query_style_target)


def render_hybrid_single_hop_system_prompt(
    *,
    corpus_summary: str,
    corpus_queries: str,
    query_style_target: str,
) -> str:
    """Render recovered Hybrid single-hop system prompt for direct generation."""
    return HYBRID_SINGLE_HOP_SYSTEM_TEMPLATE.format(
        corpus_summary=corpus_summary,
        corpus_queries=corpus_queries,
        style_instruction=render_hybrid_style_instruction(query_style_target),
    )


def render_hybrid_multi_hop_system_prompt(
    *,
    corpus_summary: str,
    corpus_queries: str,
    query_style_target: str,
) -> str:
    """Render recovered Hybrid multi-hop system prompt for direct generation."""
    return HYBRID_MULTI_HOP_SYSTEM_TEMPLATE.format(
        corpus_summary=corpus_summary,
        corpus_queries=corpus_queries,
        style_instruction=render_hybrid_style_instruction(query_style_target),
    )


def hybrid_single_hop_user_template_for_cgft() -> str:
    """Adapt recovered Hybrid single-hop user template to Cgft placeholders."""
    return (
        HYBRID_SINGLE_HOP_USER_TEMPLATE
        .replace("{prev_chunk_preview}", "(omitted)")
        .replace("{chunk_content}", "{primary_chunk}")
        .replace("{next_chunk_preview}", "{secondary_chunks}")
    )


def hybrid_multi_hop_user_template_for_cgft() -> str:
    """Adapt recovered Hybrid multi-hop user template to Cgft placeholders."""
    return (
        HYBRID_MULTI_HOP_USER_TEMPLATE
        .replace("{connecting_queries}", "{qa_type}:{target_hop_count}")
        .replace("{chunk_a_context_before}", "(omitted)")
        .replace("{chunk_a}", "{primary_chunk}")
        .replace("{chunk_a_context_after}", "(omitted)")
        .replace("{chunk_b_context_before}", "(omitted)")
        .replace("{chunk_b}", "{secondary_chunks}")
        .replace("{chunk_b_context_after}", "(omitted)")
    )


def get_hybrid_prompts() -> dict[str, str]:
    """Return a copy of recovered Hybrid prompt strings."""
    return dict(HYBRID_PROMPTS)


def get_sage_prompts() -> dict[str, str]:
    """Return a copy of recovered SAGE prompt strings."""
    return dict(SAGE_PROMPTS)
